using Asp.Versioning;using Fixar.API.Security;using Fixar.Application.Common.Models;using Fixar.Domain.Entities;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace Fixar.API.Controllers;
[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/supplier-payables"),Authorize(Policy=AuthorizationPolicies.CanViewSupplierFinance)]public class SupplierPayablesController(ApplicationDbContext db):ControllerBase{
[HttpGet]public async Task<IActionResult>List(Guid? supplierId,Guid? purchaseOrderId,string? status,string? currency,bool overdueOnly,DateTime? dueFrom,DateTime? dueTo,string? search,CancellationToken ct){var q=db.SupplierPayables.AsNoTracking().AsQueryable();if(supplierId.HasValue)q=q.Where(x=>x.SupplierId==supplierId);if(purchaseOrderId.HasValue)q=q.Where(x=>x.PurchaseOrderId==purchaseOrderId);if(!string.IsNullOrWhiteSpace(status))q=q.Where(x=>x.Status==status);if(!string.IsNullOrWhiteSpace(currency))q=q.Where(x=>x.Currency==currency.ToUpper());if(overdueOnly)q=q.Where(x=>x.OutstandingAmount>0&&x.DueDate<DateTime.UtcNow.Date);if(dueFrom.HasValue)q=q.Where(x=>x.DueDate>=dueFrom);if(dueTo.HasValue)q=q.Where(x=>x.DueDate<=dueTo);if(!string.IsNullOrWhiteSpace(search)){var s=search.ToLower();q=q.Where(x=>x.PayableNumber.ToLower().Contains(s)||x.Supplier.Name.ToLower().Contains(s));}return Ok(ApiResponse<object>.SuccessResponse(await q.OrderBy(x=>x.DueDate).Select(x=>new{x.Id,x.PayableNumber,x.SupplierId,SupplierName=x.Supplier.Name,x.PurchaseOrderId,x.PurchaseOrderNumberSnapshot,x.TransactionDate,x.DueDate,x.Currency,x.OriginalAmount,x.AllocatedAmount,x.OutstandingAmount,x.Status,OverdueDays=x.OutstandingAmount>0&&x.DueDate<DateTime.UtcNow.Date?(DateTime.UtcNow.Date-x.DueDate.Date).Days:0}).ToListAsync(ct)));}
[HttpGet("{id:guid}")]public async Task<IActionResult>Detail(Guid id,CancellationToken ct){var x=await db.SupplierPayables.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.PayableNumber,x.SupplierId,SupplierName=x.Supplier.Name,x.PurchaseOrderId,x.PurchaseOrderNumberSnapshot,x.TransactionDate,x.DueDate,x.Currency,x.OriginalAmount,x.AllocatedAmount,x.OutstandingAmount,x.Status,x.SourceType,x.Description,x.IsCancelled,x.CancellationReason}).FirstOrDefaultAsync(ct);return x is null?NotFound():Ok(ApiResponse<object>.SuccessResponse(x));}
[HttpPost,Authorize(Policy=AuthorizationPolicies.CanManageSupplierPayables),Idempotent]public async Task<IActionResult>Create(PayableRequest r,CancellationToken ct){var s=await db.Suppliers.FindAsync([r.SupplierId],ct);if(s is null)return NotFound(ApiResponse<object>.Fail("Tedarikçi bulunamadı.","SUPPLIER_NOT_FOUND"));if(r.Amount<=0)return BadRequest();await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await New(s,null,r.Amount,r.Currency,r.TransactionDate,r.DueDate,"ManualCredit",r.Description,ct);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.PayableNumber}));}
[HttpPost("{id:guid}/cancel"),Authorize(Policy=AuthorizationPolicies.CanManageSupplierPayables),Idempotent]public async Task<IActionResult>Cancel(Guid id,CancelFinanceRequest r,CancellationToken ct){var x=await db.SupplierPayables.FindAsync([id],ct);if(x is null)return NotFound();if(x.AllocatedAmount>0)return Conflict(ApiResponse<object>.Fail("Kısmi ödemesi bulunan borç doğrudan iptal edilemez.","HAS_PAYMENT"));x.IsCancelled=true;x.IsActive=false;x.Status="Cancelled";x.CancellationReason=r.Reason;x.CancelledAt=DateTime.UtcNow;db.SupplierLedgerEntries.Add(new SupplierLedgerEntry{Id=Guid.NewGuid(),EntryNumber=await SupplierFinanceSupport.Next(db,"SLE",DateTime.UtcNow,ct),SupplierId=x.SupplierId,TransactionDate=DateTime.UtcNow,EntryType="Debit",SourceType="Adjustment",SourceId=x.Id,ReferenceNumber=x.PayableNumber,Currency=x.Currency,DebitAmount=x.OutstandingAmount,Created=DateTime.UtcNow});await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
[HttpPost("{id:guid}/recalculate-status")]public async Task<IActionResult>Recalc(Guid id,CancellationToken ct){var x=await db.SupplierPayables.FindAsync([id],ct);if(x is null)return NotFound();x.Status=SupplierFinanceSupport.Status(x);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Status}));}
[HttpGet("supplier/{supplierId:guid}")]public Task<IActionResult>Supplier(Guid supplierId,CancellationToken ct)=>List(supplierId,null,null,null,false,null,null,null,ct);
[HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.SupplierPayables.AsNoTracking().Where(x=>!x.IsCancelled).GroupBy(x=>x.Currency).Select(g=>new{Currency=g.Key,Original=g.Sum(x=>x.OriginalAmount),Paid=g.Sum(x=>x.AllocatedAmount),Outstanding=g.Sum(x=>x.OutstandingAmount),Overdue=g.Where(x=>x.DueDate<DateTime.UtcNow.Date&&x.OutstandingAmount>0).Sum(x=>x.OutstandingAmount)}).ToListAsync(ct)));
[HttpGet("backfill-preview")]public async Task<IActionResult>Preview(CancellationToken ct){var rows=await db.PurchaseOrders.AsNoTracking().Where(p=>new[]{"Completed","Tamamlandı","Kapandı"}.Contains(p.Status)&&!db.SupplierPayables.Any(x=>x.PurchaseOrderId==p.Id&&!x.IsCancelled)).Select(p=>new{p.Id,PurchaseNumber=p.InvoiceNo??p.DocumentNo,Supplier=p.SupplierName,p.SupplierCode,p.GrandTotal,p.Currency,p.DueDate,Warning="Ödeme geçmişi bilinmiyor; seçilmeden borç oluşturulmaz."}).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}
[HttpPost("backfill"),Authorize(Policy=AuthorizationPolicies.CanManageSupplierPayables),Idempotent]public async Task<IActionResult>Backfill(BackfillPayables r,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var ps=await db.PurchaseOrders.Where(p=>r.PurchaseOrderIds.Contains(p.Id)).ToListAsync(ct);var made=new List<string>();foreach(var p in ps){if(await db.SupplierPayables.AnyAsync(x=>x.PurchaseOrderId==p.Id&&!x.IsCancelled,ct))continue;var s=await db.Suppliers.FirstOrDefaultAsync(x=>(p.SupplierCode!=null&&x.Code==p.SupplierCode)||x.Name==p.SupplierName,ct);if(s is null)continue;var x=await New(s,p,p.GrandTotal,p.Currency,p.OrderDate,p.DueDate??p.OrderDate.AddDays(s.PaymentTermDays??0),"PurchaseOrder","Seçili geçmiş satın alma borcu",ct);made.Add(x.PayableNumber);}await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{Created=made.Count,Numbers=made}));}
async Task<SupplierPayable>New(Supplier s,PurchaseOrder?p,decimal amount,string currency,DateTime date,DateTime due,string source,string?desc,CancellationToken ct){var x=new SupplierPayable{Id=Guid.NewGuid(),PayableNumber=await SupplierFinanceSupport.Next(db,"PAY",date,ct),SupplierId=s.Id,PurchaseOrderId=p?.Id,PurchaseOrderNumberSnapshot=p?.InvoiceNo??p?.DocumentNo,TransactionDate=date.ToUniversalTime(),DueDate=due.ToUniversalTime(),Currency=currency.ToUpper(),OriginalAmount=amount,OutstandingAmount=amount,Status=due.Date<DateTime.UtcNow.Date?"Overdue":"Open",SourceType=source,Description=desc};db.SupplierPayables.Add(x);db.SupplierLedgerEntries.Add(new SupplierLedgerEntry{Id=Guid.NewGuid(),EntryNumber=await SupplierFinanceSupport.Next(db,"SLE",date,ct),SupplierId=s.Id,TransactionDate=date,DueDate=due,EntryType="Credit",SourceType="Payable",SourceId=x.Id,ReferenceNumber=x.PayableNumber,Currency=x.Currency,CreditAmount=amount,Description=desc,Created=DateTime.UtcNow});return x;}}
public record PayableRequest(Guid SupplierId,DateTime TransactionDate,DateTime DueDate,string Currency,decimal Amount,string?Description);public record BackfillPayables(List<Guid>PurchaseOrderIds);
